# === Update .arb files ===
for locale, data in translations.items():
    filename = f"lib/l10n/app_{locale}.arb"
    with open(filename, "r", encoding="utf-8") as f:
        content = f.read()
    
    # Build key-value pairs to insert
    insert_lines = []
    for key, value in data.items():
        if key.startswith("@"):
            continue
        insert_lines.append(f'  "{key}": "{value}",')
        meta_key = f"@{key}"
        if meta_key in data:
            # This is autogenerated placeholder metadata
            if "{ms}" in value:
                insert_lines.append(f'  "@{key}": {{ "placeholders": {{ "ms": {{ "type": "int" }} }} }},')
            else:
                insert_lines.append(f'  "@{key}": {{ }},')
    
    insert_str = "\n".join(insert_lines)
    
    # Insert before the last line (which is })
    lines = content.split("\n")
    # Insert before the last line
    last_line = lines[-1]
    # Remove trailing whitespace from second-to-last line and add comma if needed
    penultimate = lines[-2].rstrip()
    if not penultimate.endswith(","):
        lines[-2] = penultimate + ","
    
    # Insert new content before closing brace
    result = "\n".join(lines[:-1]) + "\n" + insert_str + "\n" + lines[-1]
    
    with open(filename, "w", encoding="utf-8") as f:
        f.write(result)
    
    print(f"Updated {filename}")


