# For zh.dart, we need to add Simplified Chinese near line 3369 and Traditional Chinese near line 6734
# Actually, let me check the structure more carefully. The file seems to have two sections.
# Let me read it properly.

# Simpler approach: find "get logEmpty" and insert before the closing "}"
for filename, dart_code in dart_updates.items():
    filepath = f"lib/l10n/{filename}"
    with open(filepath, "r", encoding="utf-8") as f:
        content = f.read()
    
    # Find the class that has logEmpty
    # First, find the last closing brace of the file
    # The pattern is: the last getter ends with ';' then a newline then '}'
    # Let's find the last occurrence of "String get logEmpty"
    idx = content.rfind("String get logEmpty")
    # Find the end of that line
    end_idx = content.find("\n", idx)
    # Skip to after the semicolon
    semicolon_idx = content.find(";", end_idx)
    if semicolon_idx == -1:
        semicolon_idx = end_idx
    # Now find the closing brace after this
    close_brace_idx = content.find("}", semicolon_idx)
    if close_brace_idx != -1:
        content = content[:close_brace_idx] + dart_code + "\n" + content[close_brace_idx:]
    
    with open(filepath, "w", encoding="utf-8") as f:
        f.write(content)
    
    print(f"Updated {filepath}")

print("\nDone!")
